  const debouncedHandle = debounce(handleIntersect, 100);

  const spyObs = new IntersectionObserver(debouncedHandle, {
    rootMargin: "-25% 0px -65% 0px",
    threshold: 0,
  });

  sections.forEach((sec) => spyObs.observe(sec));
})();"

